// DeployAgent provisions the agent's VM: resolve pool credentials → connect
// vCenter → issue a gateway key + inject cloud-init via guestinfo → mark running.
func (r *mutationResolver) DeployAgent(ctx context.Context, input model.DeployAgentInput) (*model.DeployedAgent, error) {
	cu := auth.FromContext(ctx)
	if cu == nil {
		return nil, gqlerror.Errorf("unauthenticated")
	}
	if r.Secrets == nil || r.VCenterConnect == nil || r.Gateway == nil {
		return nil, gqlerror.Errorf("deploy is not configured (gateway/secrets/vcenter required)")
	}

	agentID, err := uuid.Parse(input.AgentID)
	if err != nil {
		return nil, gqlerror.Errorf("invalid agentId")
	}
	ag, err := r.Ent.Agent.Get(ctx, agentID)
	if err != nil {
		return nil, err
	}
	if ag.OwnerUserID.String() != cu.ID && cu.Role != auth.RoleAdmin {
		return nil, gqlerror.Errorf("forbidden: not your agent")
	}

	poolID, err := uuid.Parse(input.ResourcePoolID)
	if err != nil {
		return nil, gqlerror.Errorf("invalid resourcePoolId")
	}
	pool, err := r.Ent.ResourcePool.Get(ctx, poolID)
	if err != nil {
		return nil, err
	}
	if pool.SecretRef == "" {
		return nil, gqlerror.Errorf("resource pool has no secret_ref")
	}

	cred, err := r.Secrets.Resolve(ctx, pool.SecretRef)
	if err != nil {
		return nil, fmt.Errorf("resolve pool credentials: %w", err)
	}
	conn, err := r.VCenterConnect(ctx, pool.Endpoint, cred.Username, cred.Password, r.VCenterInsecure)
	if err != nil {
		r.audit(ctx, "agent.deploy", "agent", ag.ID.String(), false, cu.ID)
		return nil, fmt.Errorf("connect vcenter: %w", err)
	}

	svc := &deploy.Service{Gateway: r.Gateway, VCenter: conn, GatewayURL: r.GatewayURL}
	res, err := svc.Provision(ctx, deploy.Request{
		AgentName:    ag.Name,
		UserID:       ag.OwnerUserID.String(),
		Template:     input.Template,
		VMName:       input.VMName,
		ResourcePool: derefString(input.TargetResourcePool),
		Hostname:     derefString(input.Hostname),
		MaxBudget:    input.MaxBudget,
	})
	if err != nil {
		r.audit(ctx, "agent.deploy", "agent", ag.ID.String(), false, cu.ID)
		return nil, fmt.Errorf("provision: %w", err)
	}

	// Persist the issued key (secret is Sensitive) and mark the agent running.
	// Provision already succeeded: the VM is running and a live gateway key exists.
	// If either write below fails we must compensate (destroy VM + revoke key),
	// else we leak an orphan VM and an ungoverned key — the same invariant
	// deploy.Service.rollback enforces for failures *inside* Provision.
	vk, err := r.Ent.VirtualKey.Create().
		SetLitellmKey(res.VirtualKey).
		SetUserID(ag.OwnerUserID).
		SetModels([]string{"smart"}).
		SetAlias(ag.Name).
		Save(ctx)
	if err != nil {
		r.rollbackDeploy(ctx, conn, ag, input.VMName, res.VirtualKey)
		r.audit(ctx, "agent.deploy", "agent", ag.ID.String(), false, cu.ID)
		return nil, fmt.Errorf("persist virtual key failed: %w", err)
	}
	// NB: assign to a NEW var — `ag, err = Save()` would nil out `ag` on error,
	// breaking the compensation that needs the original row.
	updated, err := r.Ent.Agent.UpdateOne(ag).
		SetStatus(agent.StatusRunning).
		SetVMRef(input.VMName).
		SetVirtualKeyID(vk.ID).
		SetResourcePoolID(poolID).
		Save(ctx)
	if err != nil {
		// The vk row persisted but the agent didn't finalize; drop the now-dangling
		// row (it points at a key we're about to revoke) then compensate.
		if delErr := r.Ent.VirtualKey.DeleteOne(vk).Exec(context.WithoutCancel(ctx)); delErr != nil {
			log.Printf("deploy rollback: delete dangling vk row %s failed: %v", vk.ID, delErr)
		}
		r.rollbackDeploy(ctx, conn, ag, input.VMName, res.VirtualKey)
		r.audit(ctx, "agent.deploy", "agent", ag.ID.String(), false, cu.ID)
		return nil, fmt.Errorf("finalize agent failed: %w", err)
	}
	r.audit(ctx, "agent.deploy", "agent", updated.ID.String(), true, cu.ID)

	return &model.DeployedAgent{
		Agent:            toModelAgent(updated),
		VirtualKeySecret: res.VirtualKey,
	}, nil
}

// rollbackDeploy tears down a half-deployed agent after Provision succeeded but
// DB persistence failed: destroy the running VM, revoke the live gateway key, and
// mark the agent exception. Uses a detached context so a canceled request still
// cleans up. Best-effort — each step is logged on failure, never fatal.
func (r *Resolver) rollbackDeploy(ctx context.Context, conn VCenterClient, ag *ent.Agent, vmName, key string) {
	cctx := context.WithoutCancel(ctx)
	if err := conn.Destroy(cctx, vmName); err != nil {
		log.Printf("deploy rollback: orphan VM %q, destroy failed: %v", vmName, err)
	}
	if r.Gateway != nil {
		if err := r.Gateway.DeleteKey(cctx, key); err != nil {
			log.Printf("deploy rollback: orphan gateway key, revoke failed: %v", err)
		}
	}
	if _, err := r.Ent.Agent.UpdateOne(ag).SetStatus(agent.StatusException).Save(cctx); err != nil {
		log.Printf("deploy rollback: mark agent %s exception failed: %v", ag.ID, err)
	}
}

// RecycleAgent destroys the agent's VM, revokes its key and marks it stopped.
// Destructive — guarded by confirm + owner/admin authz + audit (LLD-03 §4 回收).
func (r *mutationResolver) RecycleAgent(ctx context.Context, input model.RecycleAgentInput) (*model.Agent, error) {
	cu := auth.FromContext(ctx)
	if cu == nil {
		return nil, gqlerror.Errorf("unauthenticated")
	}
	if !input.Confirm {
		return nil, gqlerror.Errorf("recycle is destructive: confirm must be true")
	}
	agentID, err := uuid.Parse(input.AgentID)
	if err != nil {
		return nil, gqlerror.Errorf("invalid agentId")
	}
	ag, err := r.Ent.Agent.Get(ctx, agentID)
	if err != nil {
		return nil, err
	}
	if ag.OwnerUserID.String() != cu.ID && cu.Role != auth.RoleAdmin {
		return nil, gqlerror.Errorf("forbidden: not your agent")
	}
	if ag.ResourcePoolID == nil {
		return nil, gqlerror.Errorf("agent has no resource pool; cannot locate its VM")
	}
	pool, err := r.Ent.ResourcePool.Get(ctx, *ag.ResourcePoolID)
	if err != nil {
		return nil, err
	}
	conn, err := r.connectPool(ctx, pool)
	if err != nil {
		r.audit(ctx, "agent.recycle", "agent", ag.ID.String(), false, cu.ID)
		return nil, fmt.Errorf("connect vcenter: %w", err)
	}
	defer func() { _ = conn.Logout(ctx) }()

	if ag.VMRef != "" {
		if err := conn.Destroy(ctx, ag.VMRef); err != nil {
			r.audit(ctx, "agent.recycle", "agent", ag.ID.String(), false, cu.ID)
			return nil, fmt.Errorf("destroy vm: %w", err)
		}
	}
	// Revoke the agent's gateway key so it does not outlive the VM. The VM is
	// already destroyed, so a revoke failure can't be rolled back — but it must
	// NOT be silent (that would leave an orphan key). Detached ctx: the request
	// ctx may be canceled after the slow Destroy.
	if ag.VirtualKeyID != nil && r.Gateway != nil {
		cctx := context.WithoutCancel(ctx)
		if vk, err := r.Ent.VirtualKey.Get(cctx, *ag.VirtualKeyID); err == nil {
			if delErr := r.Gateway.DeleteKey(cctx, vk.LitellmKey); delErr != nil {
				log.Printf("recycle agent %s: orphan gateway key %s, revoke failed: %v", ag.ID, vk.ID, delErr)
				r.audit(cctx, "key.revoke", "virtual_key", vk.ID.String(), false, cu.ID)
			} else {
				_, _ = r.Ent.VirtualKey.UpdateOne(vk).SetStatus(virtualkey.StatusRevoked).Save(cctx)
			}
		}
	}
	ag, err = r.Ent.Agent.UpdateOne(ag).SetStatus(agent.StatusStopped).SetVMRef("").Save(ctx)
	if err != nil {
		return nil, err
	}
	r.audit(ctx, "agent.recycle", "agent", ag.ID.String(), true, cu.ID)
	return toModelAgent(ag), nil
}

// VMTemplates lists the OVA templates available in a resource pool's vCenter,
// powering the deploy form's template picker.
func (r *queryResolver) VMTemplates(ctx context.Context, resourcePoolID string) ([]model.VMTemplate, error) {
	cu := auth.FromContext(ctx)
	if cu == nil {
		return nil, gqlerror.Errorf("unauthenticated")
	}
	// Listing templates dials the pool's vCenter with its privileged credentials,
	// so it is admin-gated like resource-pool management itself (no unauthenticated
	// or cross-tenant enumeration of another pool's inventory).
	if cu.Role != auth.RoleAdmin {
		return nil, gqlerror.Errorf("forbidden: admin only")
	}
	poolID, err := uuid.Parse(resourcePoolID)
	if err != nil {
		return nil, gqlerror.Errorf("invalid resourcePoolId")
	}
	pool, err := r.Ent.ResourcePool.Get(ctx, poolID)
	if err != nil {
		return nil, err
	}
	conn, err := r.connectPool(ctx, pool)
	if err != nil {
		return nil, fmt.Errorf("connect vcenter: %w", err)
	}
	defer func() { _ = conn.Logout(ctx) }()
	tpls, err := conn.ListTemplates(ctx)
	if err != nil {
		return nil, fmt.Errorf("list templates: %w", err)
	}
	out := make([]model.VMTemplate, 0, len(tpls))
	for _, t := range tpls {
		out = append(out, model.VMTemplate{Name: t.Name, UUID: t.UUID})
	}
	return out, nil
}
